% plot_schedulability_results.m
% MATLAB script to read and plot schedulability results from CSV
% Generated by schedulability_final.py

clear; close all; clc;

%% Read CSV file
csv_filename = 'schedulability_results.csv';
fprintf('Reading data from %s...\n', csv_filename);

% Read the CSV file
data = readtable(csv_filename);

% Extract columns
util_midpoint = data.Util_Midpoint;
hp_sched = data.HP_Schedulability;
mp_sched = data.MP_Schedulability;
lp_sched = data.LP_Schedulability;
util_ranges = data.Util_Range;

%% Create figure
figure('Position', [100, 100, 1800, 1000]);  % larger canvas for large fonts
hold on;

% Plot HP (High Priority) victims - Blue
plot(util_midpoint, hp_sched, '-^b', 'LineWidth', 8, 'MarkerSize', 25, ...
     'MarkerFaceColor', 'b', 'DisplayName', 'v: HP');

% Plot MP (Medium Priority) victims - Green
plot(util_midpoint, mp_sched, '-sg', 'LineWidth', 8, 'MarkerSize', 25, ...
     'MarkerFaceColor', 'g', 'DisplayName', 'v: MP');

% Plot LP (Low Priority) victims - Red
plot(util_midpoint, lp_sched, '-or', 'LineWidth', 8, 'MarkerSize', 25, ...
     'MarkerFaceColor', 'r', 'DisplayName', 'v: LP');

%% Formatting
xlabel('Utilization Range', 'FontSize', 45, 'FontWeight', 'bold');
ylabel('Schedulability (%)', 'FontSize', 45, 'FontWeight', 'bold');
% title('Schedulability vs Utilization for Different Victim Priority Groups', ...
%       'FontSize', 50, 'FontWeight', 'bold');

% Set axis limits
xlim([0 1.0]);
ylim([0 105]);

% Grid
grid on;

% Legend
legend('Location', 'best', 'FontSize', 40, 'Box', 'on');

% Set x-axis ticks to show utilization range labels
xticks(util_midpoint);
xticklabels(util_ranges);
xtickangle(0);

% Enhance appearance
set(gca, 'FontSize', 40, 'LineWidth', 3, 'TickLength', [0.01 0.01]);
box on;
hold off;

%% Display statistics
fprintf('\n=== Schedulability Statistics ===\n');
fprintf('Utilization Range | HP (%%) | MP (%%) | LP (%%)\n');
fprintf('-------------------------------------------\n');
for i = 1:length(util_ranges)
    fprintf('%s | %6.1f | %6.1f | %6.1f\n', ...
            util_ranges{i}, hp_sched(i), mp_sched(i), lp_sched(i));
end
fprintf('-------------------------------------------\n');
fprintf('Average:          | %6.1f | %6.1f | %6.1f\n', ...
        mean(hp_sched), mean(mp_sched), mean(lp_sched));

%% Save figure
output_filename = 'schedulability_plot.png';
saveas(gcf, output_filename);
fprintf('\n✓ Figure saved as %s\n', output_filename);

% Also save as high-resolution figure
print(gcf, 'schedulability_plot_hires.png', '-dpng', '-r300');
fprintf('✓ High-resolution figure saved as schedulability_plot_hires.png\n');

% Save as MATLAB figure
savefig(gcf, 'schedulability_plot.fig');
fprintf('✓ MATLAB figure saved as schedulability_plot.fig\n');



